const NODE_W = 130, NODE_H = 64, H_GAP = 16, V_GAP = 90;

const ANIMAL_COLORS = {
    cow:      { fill: '#fff0f0', stroke: '#c0392b', text: '#7b1a1a' },  // punane
    bull:     { fill: '#f0f4ff', stroke: '#2563eb', text: '#1e3a8a' },  // helesinine
    castrated:{ fill: '#eef2ff', stroke: '#1e3a8a', text: '#1e3a8a' },  // tumesinine
    dead:     { fill: '#E0DED8', stroke: '#B4B2A9', text: '#6b6b66' },  // hall
};

const BULL_STATUSES = new Set([3, 7, 8, 10]);


/**
 * Leiab õige värvuse vastavalt looma staatusele
 * @param status
 * @param isDead
 * @returns {{fill: string, stroke: string, text: string}}
 */
function getAnimalColors(status, isDead) {
    if (isDead) return ANIMAL_COLORS.dead;
    const s = parseInt(status);
    if (s === 9) return ANIMAL_COLORS.castrated; // härg
    if (BULL_STATUSES.has(s)) return ANIMAL_COLORS.bull;
    return ANIMAL_COLORS.cow;
}


/**
 * Leiab õige ikooni vastavalt looma staatusele
 * @param status
 * @returns {string}
 */
function getAnimalIcon(status) {
    const s = parseInt(status);
    if (s === 9) return COW_ICON_CASTRATED;
    if (BULL_STATUSES.has(s)) return COW_ICON_2;
    return COW_ICON_1;
}

// navigatsiooniriba loogika
// iga kirje salvestatakse kujul { looma_id, isokood+reg.nr }
window.animalNavHistory = window.animalNavHistory || [];

/**
 * Looma numbri ja registrinumbri navigatsiooniajalukku salvestamine.
 * @param animalId
 * @param label
 */
function pushNavHistory(animalId, label) {
    const last = window.animalNavHistory[window.animalNavHistory.length - 1];
    if (last && String(last.animalId) === String(animalId)) return;
    window.animalNavHistory.push({ animalId, label });
    renderBreadcrumb();
}


/**
 * Navigatsiooni ajalooriba loomine.
 */
function renderBreadcrumb() {
    const history = window.animalNavHistory;
    let crumbEl = document.getElementById('graph-breadcrumb');

    if (!crumbEl) { // navigatsiooniriba loomine kui varem pole tehtud
        crumbEl = document.createElement('div');
        crumbEl.id = 'graph-breadcrumb';
        crumbEl.style.cssText = `
            position: absolute;
            top: 10px;
            left: 12px;
            z-index: 20;
            display: flex;
            flex-wrap: wrap;
            align-items: center;
            gap: 4px;
            font-family: Merriweather Sans, system-ui, sans-serif;
            font-size: 12px;
            background: rgba(255,255,255,0.92);
            border: 1px solid #e0dfd9;
            border-radius: 8px;
            padding: 5px 10px;
            box-shadow: 0 2px 8px rgba(0,0,0,0.07);
            max-width: calc(100% - 24px);
        `;

        const wrapper = document.querySelector('.graph-wrapper');
        if (wrapper) {
            wrapper.style.position = 'relative';
            wrapper.appendChild(crumbEl);
        } else {
            document.getElementById('graph').appendChild(crumbEl);
        }
    }

    crumbEl.innerHTML = '';

    if (history.length <= 1) { // kui ainult üks kirje, siis peidame navigatsiooniriba
        crumbEl.style.display = 'none';
        return;
    }
    crumbEl.style.display = 'flex';

    history.forEach((entry, i) => {
        const isLast = i === history.length - 1;

        if (i > 0) {
            const sep = document.createElement('span');
            sep.textContent = '›';
            sep.style.cssText = 'color: #aaa; font-size: 13px; line-height: 1;';
            crumbEl.appendChild(sep);
        }

        const crumb = document.createElement('span');
        crumb.textContent = entry.label;
        crumb.style.cssText = isLast
            ? 'color: #333; font-weight: 600; cursor: default;'
            : 'color: #00674A; cursor: pointer; text-decoration: underline; text-underline-offset: 2px;';

        if (!isLast) {
            crumb.title = `Mine tagasi looma ${entry.label} sugupuu juurde`;
            crumb.addEventListener('click', () => {
                window.animalNavHistory = window.animalNavHistory.slice(0, i + 1); // eemaldab kõik reg.nr-d kuni vajutatud looma numbrini
                navigateToAnimal(entry.animalId, entry.label, false);
            });
        }

        crumbEl.appendChild(crumb);
    });
}

/**
 * Uue looma graafiku kuvamine pärast navigatsioonireas selle peale klõpsamist
 * @param {string|number} animalId
 * @param {string} label
 * @param {boolean} push
 */
function navigateToAnimal(animalId, label, push = true) {
    const input = document.getElementById('animalId');
    if (input) input.value = animalId;

    if (push) pushNavHistory(animalId, label); // vajutatud looma id navigatsiooniajalukku panemine
    else renderBreadcrumb();

    loadAnimalGraph();
}


/**
 * API päringu jaoks URLi koostamine vastavalt kasutaja valitud filtritele
 */
function loadAnimalGraph() {


    const animalId = parseInt(document.getElementById("animalId")?.value);
    const herdId   = document.getElementById("herdId")?.value;
    const status   = document.querySelector('select[name="status"]')?.value;
    const breed    = document.querySelector('select[name="breed"]')?.value;
    const depth    = parseInt(document.querySelector('select[name="depth"]')?.value) || 2;

    if (!animalId) {
        d3.select('#graph').html('');
        d3.select('#graph').append('div')
            .style('height', '100%')
            .style('display', 'flex')
            .style('align-items', 'center')
            .style('justify-content', 'center')
            .style('color', '#aaa')
            .style('font-size', '15px')
            .text('Vali loom, et näha selle sugupuud');
        return;
    }

    setGraphLoading(true);


    if (window.animalNavHistory.length === 0) {
        window.animalNavHistory.push({ animalId, label: String(animalId) });
    }

    const params = new URLSearchParams({
        action:    "getAnimalGraph",
        animal_id: animalId,
        herd_id:   herdId,
        depth:     depth
    });

    if (status !== 'NULL') params.append('status', status);
    if (breed  !== 'NULL') params.append('breed', breed);

    const url = window.GRAPH.moduleUrl + "&" + params.toString();

    fetch(url)
        .then(r => r.json())
        .then(json => {
            setGraphLoading(false);
            window.currentTreeData = json.data;

            const subject = json.data.find(d => parseInt(d.PEDIGREE_LEVEL) === 1);
            if (subject) {
                const realLabel = subject.REGISTERED_NUMBER || String(subject.ANIMAL_ID);
                const last = window.animalNavHistory[window.animalNavHistory.length - 1];
                if (last && String(last.animalId) === String(animalId)) {
                    last.label = realLabel;
                    renderBreadcrumb();
                }
            }

            drawAnimalGraph(json.data);
        })
        .catch(err => { // veahaldus
            setGraphLoading(false);
            console.error("Animal graph error:", err)
            d3.select('#graph').html('');
            d3.select('#graph').append('div')
                .style('height', '100%')
                .style('display', 'flex')
                .style('align-items', 'center')
                .style('justify-content', 'center')
                .style('color', '#c0392b')
                .style('font-size', '15px')
                .text('Graafiku laadimine ebaõnnestus. Palun proovi uuesti.');
        });
}


/**
 * Loomagraafiku kuvamine d3.js abil massiivist saadud andmete põhjal
 * @param data
 */
function drawAnimalGraph(data) {
    const wrapper = document.querySelector('.graph-wrapper');
    const W = wrapper.clientWidth;
    const H = wrapper.clientHeight;

    d3.select('#graph').html('');

    const svg = d3.select('#graph').append('svg')
        .attr('width', '100%').attr('height', '100%')
        .attr('viewBox', `0 0 ${W} ${H}`)
        .style('font-family', 'Merriweather Sans, system-ui, sans-serif');

    const tip = d3.select('#graph').append('div') // lisainfo kuvamine
        .style('position', 'absolute').style('pointer-events', 'none')
        .style('background', '#fff').style('border', '0.5px solid #ddd')
        .style('border-radius', '8px').style('padding', '10px 14px')
        .style('font-size', '13px').style('line-height', '1.6')
        .style('box-shadow', '0 4px 16px rgba(0,0,0,.08)')
        .style('display', 'none').style('z-index', 10).style('max-width', '280px');

    const container = svg.append('g'); // kõik elemendid siin lähevad siia sisse, et oleks võimalik suumida

    const { parents, rootData } = splitData(data);

    if (!rootData) {
        container.append('text')
            .attr('x', W / 2).attr('y', H / 2)
            .attr('text-anchor', 'middle')
            .attr('fill', '#888').text('Andmed selle looma kohta puuduvad.');
        return;
    }

    const root = d3.hierarchy(rootData, d => d.children.length ? d.children : null);

    d3.tree() // d3.tree() kasutamine järglaste kuvamiseks
        .nodeSize([NODE_W + H_GAP, NODE_H + V_GAP])
        .separation((a, b) => a.parent === b.parent ? 1 : 1.4)(root);

    const rootX = root.x;
    root.each(d => { d.x -= rootX; });

    // vanemate õigesse kohta kuvamine
    const PARENT_Y = -(NODE_H + V_GAP);
    const totalParentW = (parents.length - 1) * (NODE_W + H_GAP);
    parents.forEach((p, i) => {
        p._x = -totalParentW / 2 + i * (NODE_W + H_GAP);
        p._y = PARENT_Y;
    });


    // esialgse vaate kuvamine
    const PADDING = 60;

    const topY    = parents.length ? PARENT_Y : root.y;
    const childY  = (root.children && root.children.length)
        ? root.children[0].y + NODE_H
        : root.y + NODE_H;
    const fMinY   = topY    - PADDING;
    const fMaxY   = childY  + PADDING;

    const anchorNodes = [{ x: root.x }, ...parents.map(p => ({ x: p._x }))];
    let fMinX = Math.min(...anchorNodes.map(n => n.x))           - PADDING;
    let fMaxX = Math.max(...anchorNodes.map(n => n.x + NODE_W))  + PADDING;

    const focusH   = fMaxY - fMinY;
    const focusW   = fMaxX - fMinX;
    const fitScale = Math.min(1.0, Math.min(W / focusW, H / focusH));

    const focusCX  = (fMinX + fMaxX) / 2;
    const focusCY  = (fMinY + fMaxY) / 2;
    const initTx   = W / 2 - focusCX * fitScale;
    const initTy   = H / 2 - focusCY * fitScale;

    const zoom = d3.zoom()
        .scaleExtent([0.1, 3])
        .on('zoom', e => container.attr('transform', e.transform));

    svg.call(zoom);
    svg.call(zoom.transform, d3.zoomIdentity.translate(initTx, initTy).scale(fitScale));

    wrapper._graphZoom = zoom;
    wrapper._graphSvg  = svg;

    // servade kuvamine
    const edgeLayer = container.append('g');

    root.links().forEach(({ source: s, target: t }) => {
        const sx = s.x + NODE_W / 2, sy = s.y + NODE_H;
        const tx = t.x + NODE_W / 2, ty = t.y;
        const midY = sy + (ty - sy) / 2;
        edgeLayer.append('path')
            .attr('fill', 'none').attr('stroke', '#C8C7C2').attr('stroke-width', 1.5)
            .attr('d', `M${sx},${sy} V${midY} H${tx} V${ty}`);
    });

    if (parents.length) {
        const subX   = root.x + NODE_W / 2;
        const subTop = root.y;
        const barY   = PARENT_Y + NODE_H + (subTop - PARENT_Y - NODE_H) / 2;

        if (parents.length >= 2) {
            const leftX  = parents[0]._x + NODE_W / 2;
            const rightX = parents[parents.length - 1]._x + NODE_W / 2;

            edgeLayer.append('line')
                .attr('x1', leftX).attr('y1', barY)
                .attr('x2', rightX).attr('y2', barY)
                .attr('stroke', '#C8C7C2').attr('stroke-width', 1.5);
            edgeLayer.append('line')
                .attr('x1', (leftX + rightX) / 2).attr('y1', barY)
                .attr('x2', subX).attr('y2', subTop)
                .attr('stroke', '#C8C7C2').attr('stroke-width', 1.5);
            parents.forEach(p => {
                edgeLayer.append('line')
                    .attr('x1', p._x + NODE_W / 2).attr('y1', p._y + NODE_H)
                    .attr('x2', p._x + NODE_W / 2).attr('y2', barY)
                    .attr('stroke', '#C8C7C2').attr('stroke-width', 1.5);
            });
        } else { // ainult üks vanem
            const p = parents[0];
            const midY = (p._y + NODE_H + subTop) / 2;
            edgeLayer.append('path')
                .attr('fill', 'none').attr('stroke', '#C8C7C2').attr('stroke-width', 1.5)
                .attr('d', `M${p._x + NODE_W / 2},${p._y + NODE_H} V${midY} H${subX} V${subTop}`);
        }
    }

    // tippude ehk loomakaartide kuvamine
    const nodeLayer = container.append('g');

    root.each(d => {
        const gen       = d.depth === 0 ? 1 : d.depth + 1;
        const isSubject = d.depth === 0;
        const onSubjectClick = isSubject
            ? () => window.open(`./?module=AnimalCard&id=${d.data.id}`, '_blank')
            : null;
        drawNode(nodeLayer, d.x, d.y, d.data, gen, isSubject, tip, !isSubject, onSubjectClick);
    });

    parents.forEach(p => {
        drawNode(nodeLayer, p._x, p._y, p, 0, false, tip, true);
    });

    renderBreadcrumb(); // navigatsioonirea kuvamine

    const subjectCX = root.x + NODE_W / 2;
    const subjectCY = root.y + NODE_H / 2;

    renderZoomButtons(wrapper, zoom, svg, subjectCX, subjectCY, fitScale); // suumimispaneeli kuvamine

    renderGraphLegend(svg, W, H, [ // legendi kuvamine
        { label: "lehmik / amm / lehm", color: "#c0392b", type: "node" },
        { label: "pull / tõupull", color: "#2563eb", type: "node" },
        { label: "härg",           color: "#1e3a8a", type: "node" },
        { label: "väljaläinud loom",    color: "#B4B2A9", type: "dead"  },
    ]);

}


/**
 * Sünnipäeva õigesse formaati teisendamine.
 * @param dateStr
 * @returns {Date}
 */
function parseBirthday(dateStr) {
    if (!dateStr) return new Date(0);
    const parts = dateStr.split('.');
    if (parts.length === 3) {
        let [day, month, year] = parts;
        if (year.length === 2) year = '20' + year;
        return new Date(`${year}-${month}-${day}`);
    }
    return new Date(dateStr);
}


/**
 * Funktsioon, mis teisendab tagaliideselt saadud päringu vastuse õigele kujule.
 * @param flatData
 * @returns {{parents: *, rootData: *}|{parents: *, rootData: null}}
 */
function splitData(flatData) {
    const parents = flatData // vanemad = tase 0
        .filter(d => parseInt(d.PEDIGREE_LEVEL) === 0)
        .sort((a, b) => parseBirthday(a.BIRTHDAY) - parseBirthday(b.BIRTHDAY))
        .map(d => ({
            id:               String(d.ANIMAL_ID),
            registeredNumber: d.REGISTERED_NUMBER,
            label:            d.REGISTERED_NUMBER || String(d.ANIMAL_ID),
            born:             d.BIRTHDAY ? d.BIRTHDAY : null,
            died:             d.DATE_OF_DEATH ? d.DATE_OF_DEATH : null,
            endOfAr:          d.END_OF_AR ? d.END_OF_AR : null,
            breed:            d.BREED,
            status:           d.STATUS,
            inbr:             d.INBR,
            name:             d.NAME,
            pedigreeLevel:    0,
            children:         []
        }));

    const rootRaw = flatData.find(d => parseInt(d.PEDIGREE_LEVEL) === 1);
    if (!rootRaw) return { parents, rootData: null };

    const map = {}; // põlvkonnad 1+
    flatData.forEach(d => {
        map[String(d.ANIMAL_ID)] = {
            id:               String(d.ANIMAL_ID),
            registeredNumber: d.REGISTERED_NUMBER,
            label:            d.REGISTERED_NUMBER || String(d.ANIMAL_ID),
            born:             d.BIRTHDAY ? d.BIRTHDAY : null,
            died:             d.DATE_OF_DEATH ? d.DATE_OF_DEATH : null,
            endOfAr:          d.END_OF_AR ? d.END_OF_AR : null,
            breed:            d.BREED,
            status:           d.STATUS,
            inbr:             d.INBR,
            name:             d.NAME,
            pedigreeLevel:    parseInt(d.PEDIGREE_LEVEL),
            parentId:         d.PARENT_ID ? String(d.PARENT_ID) : null,
            children:         []
        };
    });

    flatData.forEach(d => { // järglase ja vanema ühendamine
        if (parseInt(d.PEDIGREE_LEVEL) >= 2 && d.PARENT_ID) {
            const par = map[String(d.PARENT_ID)];
            if (par) par.children.push(map[String(d.ANIMAL_ID)]);
        }
    });

    Object.values(map).forEach(node => { // loomade sorteerimine sünnikpv alusel --> kõige vanemad esimeseks
        node.children.sort((a, b) => parseBirthday(a.born) - parseBirthday(b.born));
    });

    const rootData = { ...map[String(rootRaw.ANIMAL_ID)] };

    return { parents, rootData };
}

/**
 * Graafi tipu ehk loomakaardi kuvamine. Sellele pealklikkimise funktsionaalsuse loomine
 * @param {boolean} navigable
 */
function drawNode(layer, x, y, data, gen, isSubject, tip, navigable, onSubjectClick = null) {
    const isDead = !!(data.dateOfDeath || data.died || data.endOfAr);
    const c = getAnimalColors(data.status, isDead);

    const g = layer.append('g')
        .style('cursor', (navigable || onSubjectClick) ? 'pointer' : 'default');

    g.on('mouseover', (event) => {
        tip.style('display', 'block').html(buildTooltip(data, navigable));
        moveTip(event, tip);
    })
        .on('mousemove', (event) => moveTip(event, tip))
        .on('mouseout',  () => tip.style('display', 'none'));

    if (navigable) {
        g.on('click', () => {
            tip.style('display', 'none');
            navigateToAnimal(data.id, data.label || data.registeredNumber || data.id);
        });
    }

    if (onSubjectClick) {
        g.on('click', () => {
            tip.style('display', 'none');
            onSubjectClick();
        });
    }

    if (isSubject) {
        g.append('rect')
            .attr('x', x - 4).attr('y', y - 4)
            .attr('width', NODE_W + 8).attr('height', NODE_H + 8)
            .attr('rx', 12).attr('fill', 'none')
            .attr('stroke', c.stroke).attr('stroke-width', 2.5).attr('opacity', 0.5);
    }


    const ICON_SIZE = 40;
    const iconColor = isDead ? ANIMAL_COLORS.dead.stroke : c.stroke;
    const iconPath = getAnimalIcon(data.status);
    const iconScale = ICON_SIZE / 512;

    g.append('rect')
        .attr('x', x).attr('y', y)
        .attr('width', NODE_W).attr('height', NODE_H).attr('rx', 8)
        .attr('fill', isDead ? ANIMAL_COLORS.dead.fill : c.fill)
        .attr('stroke', isDead ? ANIMAL_COLORS.dead.stroke : c.stroke)
        .attr('stroke-width', isDead ? 1 : 1.5)
        .attr('stroke-dasharray', isDead ? '4,3' : null);

    const iconX = x + NODE_W / 2 - ICON_SIZE / 2;
    const iconY = y + 4;
    g.append('g')
        .attr('transform', `translate(${iconX}, ${iconY}) scale(${iconScale})`)
        .append('path')
        .attr('d', iconPath)
        .attr('fill', iconColor);

    g.append('text')
        .attr('x', x + NODE_W / 2)
        .attr('y', y + NODE_H - 8)
        .attr('text-anchor', 'middle').attr('dominant-baseline', 'central')
        .attr('fill', isDead ? ANIMAL_COLORS.dead.text : c.text)
        .style('font-size', '12px').style('font-weight', '600')
        .text(truncate(data.label || data.registeredNumber, 16));

}


/**
 * Liiga pikkade väärtuste puhul lõigatakse lõpp ära ja lisatakse '...'
 * @param str
 * @param max
 * @returns {string|string}
 */
function truncate(str, max) {
    str = String(str ?? '');
    return str.length > max ? str.slice(0, max - 1) + '…' : str;
}


/**
 * Tooltipi HTML-i loomine
 * @param d
 * @param navigable
 * @returns {string}
 */
function buildTooltip(d, navigable) {
    const rows = [
        ['Reg. nr.', (d.label !== d.id && d.registeredNumber) ? d.registeredNumber : null],
        ['Nimi',     d.name],
        ['Tõug',     d.breed],
        ['Staatus', d.status ? (STATUS_MAP[d.status] ?? null) : null],
        ['Inbr. koef', d.inbr, '%'],
        ['Sünd',     d.born],
        ['Väljaminek', d.died || (d.dateOfDeath ? d.dateOfDeath : null)],
    ].filter(([, v]) => v != null)
        .map(([k, v, unit]) =>
            `<div style="display:flex;gap:8px;"><span style="color:#888;min-width:70px;flex-shrink:0">${k}</span><strong>${v}${unit ? unit : ''}</strong></div>`
        ).join('');

    const hint = navigable
        ? `<div style="margin-top:6px;color:#00674A;font-size:11px;">Kliki, et näha selle looma sugupuud</div>`
        : (d.pedigreeLevel === 1
            ? `<div style="margin-top:6px;color:#00674A;font-size:11px;">Kliki, et avada looma kaart</div>`
            : '');

    return rows + hint;
}

/**
 * Ei lase tooltipil graafikust välja minna, hoiab kursori lähedal.
 * @param event
 * @param tip
 */
function moveTip(event, tip) {
    const rect = event.currentTarget.closest('#graph').getBoundingClientRect();
    tip.style('left', `${event.clientX - rect.left + 14}px`)
        .style('top',  `${event.clientY - rect.top  - 10}px`);
}
